var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이걸로 정리된 건가?","JPN":"これで片づいた？","ENG":"Is this the end?","TWN":"都結束了嗎？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"굉장하군. 너희들 각자가 나이트메어에 필적하는 전투력을 가지고 있다니…….","JPN":"すごいな、お前たち。人間がナイトメアに匹敵する戦闘力を持つなんて……","ENG":"Incredible. You each possess the power of a Knightmare...","TWN":"好厲害，沒想到你們都具備足以媲美Knightmare的戰鬥力……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하하, 그걸…… 설명하자면 말이 길어지는데…….","JPN":"ははは、その辺は……説明するにはちょっと複雑だけど……","ENG":"Hah hah, it's... a long story...","TWN":"哈哈，這個嘛……說來話長……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"타피르……. 그 정도의 공격을 받고도 아직 움직일 수 있는 건가?","JPN":"タピル……あれだけの攻撃を受けてまだ動けるのか？","ENG":"Tapir... You can still move after taking all that damage?","TWN":"達爾……受到那麼強烈的攻擊卻還能動？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"어……째서…… 나는…… 모두가 만족하는…… 오늘을……","JPN":"どう……して……僕は……\\nみんなが満足する……今日を……","ENG":"Why... do this...? I... just wanted... everyone... have a perfect... day...","TWN":"為……什麼……我明明……想給大家一個……完美的今天……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"내일은…… 더 나빠질 수도 있는데…….","JPN":"明日は……今日より悪くなるかもしれないのに……","ENG":"Tomorrow... may be worse...","TWN":"明天……或許只會更糟……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래, 확실히 오늘보다 나쁜 내일이 기다리고 있을지도 모르지. 하지만 그렇다고 이대로가 괜찮다는 건 아니야.","JPN":"そうだな。確かに今日より悪い明日が待っているかもしれない。\\nだからと言って、そのままでいいはずがない。","ENG":"You're correct. Tomorrow may be worse than today. However, that doesn't mean it should be avoided.","TWN":"沒錯，明天可能會比今天更糟，但這並不表示可以將你的行為合理化。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"어……째서……","JPN":"どう……して……","ENG":"But... why...?","TWN":"為……什麼……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"인간은 더 나은 내일을 바라니까. 그것을 위해서라면 괴로워도 노력하지.","JPN":"人間はより良い明日を望むからさ。そのために、辛くても努力するんだ。","ENG":"Because mankind always looks for a brighter future. They strive to make it better, no matter the hardship.","TWN":"因為人類期待更好的明天，為此就算辛苦也還是努力堅持。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_SHORT","text":{"KOREA":"맞아. 내일이 있으니까 사람은 살아갈 수 있어.","JPN":"そうね。明日があるから人は生きられる。","ENG":"He's right. We keep moving forward because there is a tomorrow.","TWN":"沒錯，就是因為有明天，人們才可以活下去。"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_GEASS_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"똑같은 매일을 반복하는 것으로는 살아있다고 할 수 없지.","JPN":"同じ毎日を過ごすことを生きているとは言い難いからな。","ENG":"Reliving the same day can't be called living.","TWN":"重複過同一天並不算是活著。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그래, 비록 시간이 걸리더라도 인간은 끊임없이 행복을 추구하니까.","JPN":"だから、人間は少しでも良い未来にするため、幸せな明日を求めて生きるんだ。","ENG":"Yes. Humans will continue to seek happiness, even if it takes time.","TWN":"沒錯，不管要花多長的時間，人類都不會放棄追求幸福的。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그래. 역시 가짜 학원제로는 안 되는 거라구.","JPN":"そっか。そうだよね。やっぱり、偽物の学園祭じゃダメだったんだ。","ENG":"Yeah. And having a fake festival just won't do it.","TWN":"說的好！假的學園祭果然還是不行！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"모두 함께 매일매일 학원제를 준비하는 건 즐거웠지만…… 그건 내일 학원제의 성공을 바랐기 때문에 즐거웠던 거야.","JPN":"学園祭を成功させるために、みんなで色々考えて、準備するのは、\\nすごく楽しかった。でも、それは明日に控えた学園祭の成功を想っていたから。","ENG":"It was fun preparing for it every day... But that's because we all hoped it would lead to a successful festival the next day.","TWN":"雖然我很享受大家每天一起準備學園祭的時間……但那也是因為我期待明天的學園祭可以成功。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"내일이 오지 않는 매일은 즐거웠지만…… 결국, 즐겁지 않은 거라구!!","JPN":"そんな明日が来ない毎日は楽しいけど、楽しくない。","ENG":"It was fun to repeat today without a tomorrow... But it's ultimately no fun at all!!","TWN":"沒有明天的每一天也很快樂……但結果而言還是不快樂的！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그러니까…… 두고 봐! 타피르 선배!","JPN":"だからね、タピル先輩。今に見てて！","ENG":"So... Just watch, Tapir!","TWN":"所以…達爾前輩！你等著吧！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"다음에는 꿈 같은 게 아니라 <color=#ffd34c>진짜</color>로 주인공이 되어 보일 테니까!!","JPN":"今度は夢なんかじゃなくて<color=#ffd34c>本物</color>の主人公になってみせるから！！","ENG":"Next time, I'll be the <color=#ffd34c>true</color> star of the festival! And not in some dream!!","TWN":"下一次不會是在夢境裡，我會在現實生活中成為<color=#ffd34c>真正</color>的主角！！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양…….","JPN":"ナイエルさん……","ENG":"Naielle...","TWN":"奈爾……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"생각한 대로야. 이 세계가 붕괴하기 시작했어.","JPN":"思ったとおりだ。この世界の構築が崩れ始めたぞ。","ENG":"Just as I thought. This world has started to collapse.","TWN":"如我所料，這個世界開始瓦解。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"C.C._GEASS_NULL_LIMITED","text":{"KOREA":"이제 곧 각각 원래 세계로 돌아갈 수 있을 거야.","JPN":"まもなくそれぞれ元の世界に戻れるだろう。","ENG":"We'll soon be able to return to our respective worlds.","TWN":"大家應該很快就可以回到各自的世界。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"C.C._GEASS_NULL_LIMITED","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 여기서 작별이라는 거네?","JPN":"じゃあ、ここでお別れということ？","ENG":"Then, is this goodbye?","TWN":"那是說再見的時候囉？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LELOUCH_GEASS_NULL_SHORT","text":{"KOREA":"그렇게 되겠군.","JPN":"そうなるな。","ENG":"I believe so.","TWN":"沒錯。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"LELOUCH_GEASS_NULL_SHORT","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};